package server
import("encoding/csv";"encoding/json";"encoding/xml";"fmt";"net/http";"strings";"time")
func(s *Server)handleTransform(w http.ResponseWriter,r *http.Request){from:=r.URL.Query().Get("from");to:=r.URL.Query().Get("to");if from==""||to==""{writeError(w,400,"from and to required");return};var body map[string]interface{};var bodyStr string;t0:=time.Now();if from=="json"{json.NewDecoder(r.Body).Decode(&body)}else if from=="csv"{rdr:=csv.NewReader(r.Body);recs,_:=rdr.ReadAll();body=map[string]interface{}{"rows":recs}}else{buf:=new(strings.Builder);xml.NewDecoder(r.Body).Decode(&body);bodyStr=buf.String();_=bodyStr};var out[]byte;var err error;switch to{case"json":out,err=json.Marshal(body);case"csv":var sb strings.Builder;cw:=csv.NewWriter(&sb);if rows,ok:=body["rows"].([]interface{});ok{for _,row:=range rows{if r2,ok2:=row.([]interface{});ok2{strs:=make([]string,len(r2));for i,v:=range r2{strs[i]=fmt.Sprint(v)};cw.Write(strs)}}};cw.Flush();out=[]byte(sb.String());default:out,err=json.Marshal(body)};dur:=time.Since(t0).Milliseconds();if err!=nil{writeError(w,500,err.Error());return};s.db.Record(from,to,int(r.ContentLength),len(out),dur);w.Header().Set("Content-Type","application/json");w.Write(out)}
func(s *Server)handleOverview(w http.ResponseWriter,r *http.Request){m,_:=s.db.Stats();writeJSON(w,200,m)}
